let replaceCover = (u) => {
    if (u.startsWith("https://")) u = u.substring(8)
    else u = u.substring(7)
    let uArr = u.split("/")
    uArr[0] = "https://p6-novel.byteimg.com/origin"
    let uArr2 = []
    uArr.forEach((x) => {
        if (!x.includes("?") && !x.includes("~")) uArr2.push(x)
        else uArr2.push(x.split("~")[0])
    })
    u = uArr2.join("/")
    return u
}

const api = "http://xindmian.xuanbao.icu";

function findContentUrl(itemId) {
	   const { source, java } = this;

	   let cas = source.getLoginInfoMap().get("来源验证");
	   let key = source.getLoginInfoMap().get("填入你的专属Key");

	   let header = {
	   	    "Key": key,
	   	    "Time-Token": Date.now(),
	   	    "X-Novel-Type": "read.yuedu"
	   	}

    const action = `${api}/fanqienovel/api/content.php?source=${java.encodeURI(cas)}&item_id=${itemId},` + JSON.stringify({headers: header});

    return action
}

